import React from 'react'
import { Img_URL } from '../../utils/fetchApi';
import { Link } from 'react-router-dom';

const Genres = () => {
  const [page,setPage]=useState(1);
  const [popularMovieList,setPopularMovieList]=useState([])

  const loadMoreHandle=()=>{
   setPage((prev)=> {
    console.log(prev);
    return prev += 1;
   });
   refetch();
   setPopularMovieList((prev)=> [...prev,...PopularList]);
 }

  const { isLoading,isError,error ,data: PopularList,refetch} = useQuery({
      queryKey: ["PopularList"],
      // keepPreviousData: true,
      // staleTime:60000,
      queryFn: () =>
        fetchMovieList("popular",`${page}`).then((res) => {
          if(page===1){
            setPopularMovieList(res.results);
          }
          console.log(res.results);
          return res.results;
        }),
    });



    useEffect(()=>{
      refetch();
    },[refetch,page]);

    if (isLoading) {
      return (
        <div className="loading">
          <h1>Loading...</h1>
        </div>
      );
    } else if (isError) {
      return (
        <div className="error">
          <p>{error.message}</p>
        </div>
      );
    } else
return (
  <div className="Popular">
        <h1>Popular Movies</h1>
        <div>
        {popularMovieList?.map((item,index) => (
            <Link to={`/movie/${item.id}`} className="card" key={index}>
              <img src={`${Img_URL}${item.poster_path}`} alt="img" />
            </Link>
        ))}
        </div>
        <button onClick={loadMoreHandle}>More</button>
      </div>
)
}

export default Genres
